import scala.collection.mutable.PriorityQueue

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
   val rows = m.toInt
   val cols = n.toInt
   val INF = Long.MaxValue
   val dist = Array.ofDim[Long](rows, cols, 2)
   for (i <- 0 until rows) {
      for (j <- 0 until cols) {
         dist(i)(j)(0) = INF
         dist(i)(j)(1) = INF
      }
   }
   dist(0)(0)(1) = 1
   val pq = PriorityQueue[(Long, Int, Int, Int)]()
   pq.enqueue((1, 0, 0, 1))
   while (pq.nonEmpty) {
      val (currentCost, i, j, p) = pq.dequeue()
      if (i == rows - 1 && j == cols - 1) return currentCost
      if (currentCost > dist(i)(j)(p)) {
         // skip this state
      } else {
         if (p == 1) {
            if (j + 1 < cols) {
               val newI = i
               val newJ = j + 1
               val newCost = currentCost + (newI + 1) * (newJ + 1)
               if (newCost < dist(newI)(newJ)(0)) {
                  dist(newI)(newJ)(0) = newCost
                  pq.enqueue((newCost, newI, newJ, 0))
               }
            }
            if (i + 1 < rows) {
               val newI = i + 1
               val newJ = j
               val newCost = currentCost + (newI + 1) * (newJ + 1)
               if (newCost < dist(newI)(newJ)(0)) {
                  dist(newI)(newJ)(0) = newCost
                  pq.enqueue((newCost, newI, newJ, 0))
               }
            }
         } else {
            val newI = i
            val newJ = j
            val newCost = currentCost + waitCost(i)(j)
            if (newCost < dist(newI)(newJ)(1)) {
               dist(newI)(newJ)(1) = newCost
               pq.enqueue((newCost, newI, newJ, 1))
            }
         }
      }
   }
   -1
}
